import { useQuery } from '@tanstack/react-query';
import { ordersApi } from '../../services/api';

function OrderDetails({ orderId }) {
  const { data: order, isLoading, error } = useQuery({
    queryKey: ['order', orderId],
    queryFn: () => ordersApi.getOrderById(orderId),
    enabled: !!orderId, // ne s'exécute que si orderId existe
    staleTime: 10 * 60 * 1000, // 10 minutes de cache
  });

  if (isLoading) {
    return <div className="text-center py-8">Chargement de la commande...</div>;
  }

  if (error) {
    return (
      <div className="text-red-500 text-center py-8">
        Erreur : {error.message}
      </div>
    );
  }

  if (!order) return null;

  return (
    <div className="p-4 border rounded-lg">
      <h2 className="text-xl font-bold">Commande {order.orderNumber}</h2>
      <p>Date : {new Date(order.createdAt).toLocaleDateString()}</p>
      <p>Total : {order.total.toFixed(2)} €</p>
      <h3 className="font-semibold mt-4">Produits :</h3>
      <ul>
        {order.items.map(item => (
          <li key={item.id}>{item.name} x {item.quantity} = {item.price * item.quantity} €</li>
        ))}
      </ul>
    </div>
  );
}
