// hooks/useOrderStatus.js
import { useQuery } from '@tanstack/react-query';
import { ordersApi } from '../services/api';

const FINAL_STATUSES = ['delivered', 'cancelled'];

export const useOrderStatus = (orderId, enabled = true) => {
  const query = useQuery({
    queryKey: ['orderStatus', orderId],
    queryFn: () => ordersApi.getOrderStatus(orderId),
    enabled: enabled && !!orderId,
    refetchInterval: (query) => {
      const status = query.state.data?.status;
      // Arrêter le polling si statut final atteint
      if (status && FINAL_STATUSES.includes(status)) {
        return false;
      }
      return 30000; // 30 secondes
    },
    staleTime: 0, // Toujours considéré stale pour rafraîchir
    refetchOnWindowFocus: true, // Rafraîchir quand l'onglet redevient actif
  });

  return {
    status: query.data?.status,
    isPolling: query.isFetching,
    isFinal: query.data?.status && FINAL_STATUSES.includes(query.data.status),
    ...query
  };
};

// Utilisation dans OrderDetails
const OrderStatusTracker = ({ orderId }) => {
  const { status, isPolling, isFinal } = useOrderStatus(orderId);

  return (
    <div className="flex items-center gap-2">
      <span className="font-semibold">Statut :</span>
      <StatusBadge status={status} />
      {isPolling && !isFinal && (
        <span className="text-xs text-gray-400 animate-pulse">
          Mise à jour automatique...
        </span>
      )}
    </div>
  );
};
